        "  break;\n" +
        "}",
        "");
    foldSame("switch ('fallThru') {\n" +
        "case 'fallThru':\n" +
        "  if (foo(123) > 0) {\n" +
        "    foobar(1);\n" +
        "    break;\n" +
        "  }\n" +
        "  foobar(2);\n" +
        "case 'bar':\n" +
        "  bar();\n" +
        "}");
    foldSame("switch ('fallThru') {\n" +
        "case 'fallThru':\n" +
        "  foo();\n" +
        "case 'bar':\n" +
        "  bar();\n" +
        "}");
    foldSame("switch ('hasDefaultCase') {\n" +
        "case 'foo':\n" +
        "  foo();\n" +
        "  break;\n" +
        "default:\n" +
        "  bar();\n" +
        "  break;\n" +
        "}");
    fold("switch ('repeated') {\n" +
        "case 'repeated':\n" +
        "  foo();\n" +
        "  break;\n" +
        "case 'repeated':\n" +
        "  bar();\n" +
        "  break;\n" +
        "}",
        "{foo();}");
    fold("switch ('foo') {\n" +
        "case 'bar':\n" +
        "  bar();\n" +
        "  break;\n" +
        "case notConstant:\n" +
        "  foobar();\n" +
        "  break;\n" +
        "case 'foo':\n" +
        "  foo();\n" +
        "  break;\n" +
        "}",
        "switch ('foo') {\n" +
        "case notConstant:\n" +
        "  foobar();\n" +
        "  break;\n" +
        "case 'foo':\n" +
        "  foo();\n" +
        "  break;\n" +
        "}");
    fold("switch (1) {\n" +
        "case 1:\n" +
        "  foo();\n" +
        "  break;\n" +
        "case 2:\n" +
        "  bar();\n" +
        "  break;\n" +
        "}",
        "{foo();}");
    fold("switch (1) {\n" +
        "case 1.1:\n" +
        "  foo();\n" +
        "  break;\n" +
        "case 2:\n" +
        "  bar();\n" +
        "  break;\n" +
        "}",
        "");
    foldSame("switch (0) {\n" +
        "case NaN:\n" +
        "  foobar();\n" +
        "  break;\n" +
        "case -0.0:\n" +
        "  foo();\n" +
        "  break;\n" +
        "case 2:\n" +
        "  bar();\n" +
        "  break;\n" +
        "}");
    foldSame("switch ('\\v') {\n" +
        "case '\\u000B':\n" +
        "  foo();\n" +
        "}");
    foldSame("switch ('empty') {\n" +
        "case 'empty':\n" +
        "case 'foo':\n" +
        "  foo();\n" +
        "}");
  }

